scwin.f_openPopUp = async function () {
  let args = new Array();
  args[0] = ed_cvsslMgntNo.getValue(); //본선관리번호
  args[1] = ''; //수출입구분코드

  let rtnValues = await $c.win.openPopup($p, "/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml", {
    title: "본선관리번호검색팝업",
    popupName: "본선관리번호검색화면",
    type: 'browserPopup',
    width: 1080,
    height: 650
  }, args);
  if (rtnValues != null) {
    ed_cvsslMgntNo.setValue(rtnValues[0]);
  }
};
scwin.sbm_save_submitdone = async function (e) {
  var result = e.responseJSON?.resultDataSet?.[0];
  if (!result) return;
  if (result.Msg === "SUCC") {
    await $c.gus.cfAlertMsg($p, MSG_CM_INF_001);
    scwin.f_RetrieveShiftingResults();
  }
};
scwin.sbm_condition_submitdone = async function (e) {
  var result = e.responseJSON?.resultDataSet?.[0];
  if (!result) return;
  if (result.Msg !== "SUCC") return;
  scwin.f_DivHoldEachWorkPlanList();

  // 본선기본정보 DataSet
  // GAUCE: ds_carryingVesselCompletionInformation event=OnLoadCompleted(rowCnt)
  scwin.f_CarryingVesselCompletionInformation();
  let rowCntCompletion = ds_carryingVesselCompletionInformation.getRowCount();
  let saveCheck = 0;
  for (let i = 0; i < rowCntCompletion; i++) {
    if (ds_carryingVesselCompletionInformation.getCellData(i, "cvsslWrkCompleteYn") == "0") {
      saveCheck = saveCheck + 1;
    }
  }
  if (rowCntCompletion == saveCheck) {
    $c.gus.cfDisableBtn($p, [btn_save, btn_AddShift, btn_DeleteShift, btn_CancelShift, btn_Caculate]);
    gr_cargoShiftingResults.setReadOnly("grid", true);
  } else {
    $c.gus.cfEnableObjects($p, [btn_save, btn_AddShift, btn_DeleteShift, btn_CancelShift, btn_Caculate]);
    gr_cargoShiftingResults.setReadOnly("grid", false);
  }
  for (let i = 0; i < rowCntCompletion; i++) {
    if (i + 1 < rowCntCompletion) {
      if (ds_carryingVesselCompletionInformation.getCellData(i, "cvsslWrkCompleteDt") >= ds_carryingVesselCompletionInformation.getCellData(i + 1, "cvsslWrkCompleteDt")) {
        ds_carryingVesselCompletionInformation.setCellData(0, "cvsslWrkCompleteDt", ds_carryingVesselCompletionInformation.getCellData(i, "cvsslWrkCompleteDt"));
        if (ds_carryingVesselCompletionInformation.getRowCount() > 1) {
          ds_carryingVesselCompletionInformation.setCellData(1, "cvsslWrkCompleteDt", ds_carryingVesselCompletionInformation.getCellData(i, "cvsslWrkCompleteDt"));
        }
      } else {
        ds_carryingVesselCompletionInformation.setCellData(0, "cvsslWrkCompleteDt", ds_carryingVesselCompletionInformation.getCellData(i + 1, "cvsslWrkCompleteDt"));
        if (ds_carryingVesselCompletionInformation.getRowCount() > 1) {
          ds_carryingVesselCompletionInformation.setCellData(1, "cvsslWrkCompleteDt", ds_carryingVesselCompletionInformation.getCellData(i + 1, "cvsslWrkCompleteDt"));
        }
      }
    }
  }
  let rowCntShifting = ds_ShiftingResults.getRowCount();
  totalRows1.setValue(rowCntShifting);

  // 본선기본정보 DataSet
  // ds_cargoShiftingResults >> onLoadComplete(rowCnt)
  let rowCntCargo = ds_cargoShiftingResults.getRowCount();
  totalRows2.setValue(rowCntCargo);
  scwin.imptotal = 0;
  scwin.exptotal = 0;
  if (rowCntCargo == 0 && rowCntShifting == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_003);
    $c.gus.cfDisableBtn($p, [btn_save, btn_AddShift, btn_DeleteShift, btn_CancelShift, btn_Caculate]); // 본선미완료시 매출생성 못함
    gr_cargoShiftingResults.setReadOnly("grid", true);
    return false;
  }

  // OUT_DS4
  if (rowCntShifting > 0) {
    if (rowCntCargo == 0) {
      ds_cargoShiftingResults.setJSON(ds_ShiftingResults.getAllJSON());
      for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        ds_cargoShiftingResults.setCellData(i, "adptQty", ds_ShiftingResults.getCellData(i, "rsltsQty"));
        ds_cargoShiftingResults.setCellData(i, "adptWt", ds_ShiftingResults.getCellData(i, "rsltsWt"));
        ds_cargoShiftingResults.setCellData(i, "adptCbm", ds_ShiftingResults.getCellData(i, "rsltsCbm"));
        if (ds_cargoShiftingResults.getCellData(i, "impExpClsCd") == "I") {
          scwin.imptotal = scwin.imptotal + 1;
        } else if (ds_cargoShiftingResults.getCellData(i, "impExpClsCd") == "O") {
          scwin.exptotal = scwin.exptotal + 1;
        }
      }
      for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        ds_cargoShiftingResults.setCellData(i, "impTotal", scwin.imptotal);
        ds_cargoShiftingResults.setCellData(i, "expTotal", scwin.exptotal);
      }
    } else {
      for (let i = 0; i < rowCntShifting; i++) {
        let check = 0;
        for (let j = 0; j < ds_cargoShiftingResults.getRowCount(); j++) {
          if (ds_ShiftingResults.getCellData(i, "impExpClsCd") == ds_cargoShiftingResults.getCellData(j, "impExpClsCd") && ds_ShiftingResults.getCellData(i, "commCd") == ds_cargoShiftingResults.getCellData(j, "commCd") && ds_ShiftingResults.getCellData(i, "wrkStpCd") == ds_cargoShiftingResults.getCellData(j, "wrkStpCd")) {
            check++;
          }
        }
        if (check == 0) {
          let importRow = ds_cargoShiftingResults.insertRow();
          ds_cargoShiftingResults.setRowJSON(importRow, ds_ShiftingResults.getRowJSON(i));
          ds_cargoShiftingResults.setCellData(importRow, "adptQty", ds_ShiftingResults.getCellData(i, "rsltsQty"));
          ds_cargoShiftingResults.setCellData(importRow, "adptWt", ds_ShiftingResults.getCellData(i, "rsltsWt"));
          ds_cargoShiftingResults.setCellData(importRow, "adptCbm", ds_ShiftingResults.getCellData(i, "rsltsCbm"));
        }
      }
    }
    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
      if (ds_cargoShiftingResults.getCellData(i, "selpchItemCd") == "") {
        let wrkStpCd = ds_cargoShiftingResults.getCellData(i, "wrkStpCd");
        if (wrkStpCd == "0007") {
          if (ds_cargoShiftingResults.getCellData(i, "sellClsCd") == "N") {
            scwin.clsCd = 1;
            scwin.filterSelpchItemCd(wrkStpCd);
            ds_cargoShiftingResults.setCellData(i, "selpchItemCd", ds_sellingItem.getCellData(0, "sellItemCd"));
          }
        } else if (wrkStpCd == "0008") {
          if (ds_cargoShiftingResults.getCellData(i, "sellClsCd") == "N") {
            scwin.clsCd = 2;
            // ds_sellingItem 필터는 해당 cell 수정 시에 적용
            scwin.filterSelpchItemCd(wrkStpCd);
            ds_cargoShiftingResults.setCellData(i, "selpchItemCd", ds_sellingItem.getCellData(0, "sellItemCd"));
          }
        }
        ds_sellingItem.clearFilter();
      }
    }
  }

  // OUT_DS2
  if (rowCntCargo > 0) {
    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
      if (ds_cargoShiftingResults.getCellData(i, "impExpClsCd") == "I") {
        scwin.imptotal = scwin.imptotal + 1;
      } else if (ds_cargoShiftingResults.getCellData(i, "impExpClsCd") == "O") {
        scwin.exptotal = scwin.exptotal + 1;
      }
    }
    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
      ds_cargoShiftingResults.setCellData(i, "impTotal", scwin.imptotal);
      ds_cargoShiftingResults.setCellData(i, "expTotal", scwin.exptotal);
    }
  }
  for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
    dma_conditionContract.set("cvsslMgntNo", ds_cargoShiftingResults.getCellData(i, "cvsslMgntNo"));
    dma_conditionContract.set("wrkStpCd", ds_cargoShiftingResults.getCellData(i, "wrkStpCd"));
    dma_conditionContract.set("odrKndCd", ds_cargoShiftingResults.getCellData(i, "odrKndCd"));
    ds_ctrtNo.removeAll();
    await $c.sbm.execute($p, sbm_contractInformation);
    if (ds_ctrtNo.getRowCount() == 0) {
      $c.gus.cfAlertMsg($p, "해당 본선의 계약번호가 없습니다.");
    } else {
      var cargoCrtNo = ds_cargoShiftingResults.getCellData(i, "ctrtNo");
      var matchIdx = scwin.findRowByValue(ds_ctrtNo, "ctrtNo", cargoCrtNo);
      if (matchIdx > -1) {
        ds_cargoShiftingResults.setCellData(i, "ctrtNoDetail", ds_ctrtNo.getCellData(matchIdx, "ctrtNoDetail"));
      }
      var options = {};
      options.sortIndex = "ctrtNo ctrtWrkPathNm taxnClsCd";
      options.sortOrder = "-1 1 -1"; // 내림차순 (DESC): -1, 오름차순 (ASC): 1

      ds_ctrtNo.multisort(options);
      if (ds_cargoShiftingResults.getCellData(i, "sellClsCd") === "N") {
        ds_cargoShiftingResults.setCellData(i, "ctrtNo", ds_ctrtNo.getCellData(0, "ctrtNo"));
        ds_cargoShiftingResults.setCellData(i, "ctrtNoDetail", ds_ctrtNo.getCellData(0, "ctrtNoDetail"));
        ds_cargoShiftingResults.setCellData(i, "ctrtWrkPathSeq", ds_ctrtNo.getCellData(0, "ctrtWrkPathSeq"));
        ds_cargoShiftingResults.setCellData(i, "ctrtWrkStpSeq", ds_ctrtNo.getCellData(0, "ctrtWrkStpSeq"));
        ds_cargoShiftingResults.setCellData(i, "taxnClsCd", ds_ctrtNo.getCellData(0, "taxnClsCd"));
        ds_cargoShiftingResults.setCellData(i, "berthCd", ds_ctrtNo.getCellData(0, "berthCd"));
      }
    }
  }
  for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
    ds_caculateShiftingSelling.setJSON([{
      "crcCd": ds_cargoShiftingResults.getCellData(i, "crcCd"),
      "stdDt": ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt") ?? ""
    }]);
    await $c.sbm.execute($p, sbm_ExchRate);
    let stdExchRt = ds_ExchRate.getRowCount() > 0 ? ds_ExchRate.getCellData(0, "stdExchRt") : "0";
    ds_cargoShiftingResults.setCellData(i, "stdExchRt", stdExchRt);
  }

  //ds_cargoShiftingResults.modifyAllStatus("R"); // 모든 행을 초기 상태로 변경
  ds_cargoShiftingResults.reform();
  ds_caculateShiftingSellingHidden1.removeAll();
  ds_caculateShiftingSellingHidden1.setJSON(ds_cargoShiftingResults.getAllJSON());
};
scwin.findRowByValue = function (ds, colId, value) {
  for (var i = 0; i < ds.getRowCount(); i++) {
    if (ds.getCellData(i, colId) == value) {
      return i;
    }
  }
  return -1;
};

// SHIFTING매출 그리드  체크박스 클릭시 (gr_cargoShiftingResults OnClick)
scwin.gr_cargoShiftingResults_oncellclick = async function (rowIndex, columnIndex, columnId) {
  if (columnId !== "chk") return;
  if (ds_cargoShiftingResults.getCellData(rowIndex, "chk") === "1") {
    let impExpClsCd = ds_cargoShiftingResults.getCellData(rowIndex, "impExpClsCd");
    let targetClsCd = impExpClsCd === "I" ? "I" : "O";
    let msgPrefix = impExpClsCd === "I" ? "수입" : "수출";
    let rowCnt = ds_carryingVesselCompletionInformation.getRowCount();
    for (let i = 0; i < rowCnt; i++) {
      if (ds_carryingVesselCompletionInformation.getCellData(i, "impExpClsCd") === targetClsCd) {
        if (ds_carryingVesselCompletionInformation.getCellData(i, "cvsslWrkCompleteYn") == "0") {
          // 본선미완료이면
          await $c.gus.cfAlertMsg($p, msgPrefix + "본선은 완료가 되지 않아 SHIFTING매출을 생성 하실수가 없습니다.");
          ds_cargoShiftingResults.setCellData(rowIndex, "chk", "0");
          $c.gus.cfDisableBtnOnly($p, [btn_AddShift, btn_DeleteShift]);
          return;
        } else {
          ds_cargoShiftingResults.setCellData(rowIndex, "chk", "1");
          $c.gus.cfEnableBtnOnly($p, [btn_AddShift, btn_DeleteShift]);
        }
      }
    }
  }
};
// 행추가시 계약번호 알림 alert는 미표시
scwin.flagAddRow = false;
scwin.gr_cargoShiftingResults_onrowindexchange = async function (rowIndex, oldRow) {
  if (rowIndex < 0) return;
  let crcCd = ds_cargoShiftingResults.getCellData(rowIndex, "crcCd");
  if (crcCd === "KRW") {
    gr_cargoShiftingResults.setReadOnly("column", "sellCtrlAmtFcrc", true);
    gr_cargoShiftingResults.setReadOnly("column", "sellCtrlAmt", false);
  } else {
    gr_cargoShiftingResults.setReadOnly("column", "sellCtrlAmtFcrc", false);
    gr_cargoShiftingResults.setReadOnly("column", "sellCtrlAmt", true);
  }

  // GAUS와 동일하게 sellClsCd=="N" 인 경우만 계약번호 조회
  if (ds_cargoShiftingResults.getCellData(rowIndex, "sellClsCd") === "N") {
    dma_conditionContract.set("cvsslMgntNo", ds_cargoShiftingResults.getCellData(rowIndex, "cvsslMgntNo"));
    dma_conditionContract.set("wrkStpCd", ds_cargoShiftingResults.getCellData(rowIndex, "wrkStpCd"));
    dma_conditionContract.set("odrKndCd", ds_cargoShiftingResults.getCellData(rowIndex, "odrKndCd"));
    ds_ctrtNo.removeAll();
    await $c.sbm.execute($p, sbm_contractInformation);
    if (ds_ctrtNo.getRowCount() == 0) {
      $c.gus.cfAlertMsg($p, "해당 본선의 계약번호가 없습니다.");
      // if (scwin.flagAddRow) {
      //     scwin.flagAddRow = false;
      // } else {
      //     $c.gus.cfAlertMsg("해당 본선의 계약번호가 없습니다.");
      // }
    } else {
      var options = {};
      options.sortIndex = "ctrtNo ctrtWrkPathNm taxnClsCd";
      options.sortOrder = "-1 1 -1"; // 내림차순 (DESC): -1, 오름차순 (ASC): 1
      ds_ctrtNo.multisort(options);
      ds_cargoShiftingResults.setCellData(rowIndex, "ctrtNo", ds_ctrtNo.getCellData(0, "ctrtNo"));
      ds_cargoShiftingResults.setCellData(rowIndex, "ctrtNoDetail", ds_ctrtNo.getCellData(0, "ctrtNoDetail"));
      ds_cargoShiftingResults.setCellData(rowIndex, "ctrtWrkPathSeq", ds_ctrtNo.getCellData(0, "ctrtWrkPathSeq"));
      ds_cargoShiftingResults.setCellData(rowIndex, "ctrtWrkStpSeq", ds_ctrtNo.getCellData(0, "ctrtWrkStpSeq"));
      ds_cargoShiftingResults.setCellData(rowIndex, "taxnClsCd", ds_ctrtNo.getCellData(0, "taxnClsCd"));
      ds_cargoShiftingResults.setCellData(rowIndex, "berthCd", ds_ctrtNo.getCellData(0, "berthCd"));
      gr_cargoShiftingResults.refreshCell(rowIndex, "ctrtNoDetail");
    }
  }

  // gr_cargoShiftingResults.setCellInputType(rowIndex, "ctrtNoDetail", { inputType: "text" });
};
scwin.gr_cargoShiftingResults_onviewchange = async function (info) {
  // 예시: {"oldValue":"","newValue":"101","rowIndex":1,"colIndex":0,"colId":"wrkPlCd"}
  let rowIndex = info.rowIndex;
  let colid = info.colId;
  let oldValue = info.oldValue;
  let newValue = info.newValue;
  switch (colid) {
    case "ctrtNoDetail":
      if (oldValue === newValue) break;
      ds_cargoShiftingResults.setCellData(rowIndex, "sellAmt", 0);
      ds_cargoShiftingResults.setCellData(rowIndex, "sellAmtFcrc", 0);
      ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmt", 0);
      ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmtFcrc", 0);
      ds_cargoShiftingResults.setCellData(rowIndex, "ctrtTrf", 0);
      ds_cargoShiftingResults.setCellData(rowIndex, "crcCd", "");
      ds_cargoShiftingResults.setCellData(rowIndex, "unitNm", "");
      let ctrtNorow = ds_ctrtNo.getMatchedIndex("ctrtNoDetail", newValue);
      if (ctrtNorow.length > 0) {
        ds_cargoShiftingResults.setCellData(rowIndex, "ctrtNo", ds_ctrtNo.getCellData(ctrtNorow[0], "ctrtNo"));
        ds_cargoShiftingResults.setCellData(rowIndex, "ctrtWrkPathSeq", ds_ctrtNo.getCellData(ctrtNorow[0], "ctrtWrkPathSeq"));
        ds_cargoShiftingResults.setCellData(rowIndex, "ctrtWrkStpSeq", ds_ctrtNo.getCellData(ctrtNorow[0], "ctrtWrkStpSeq"));
        ds_cargoShiftingResults.setCellData(rowIndex, "taxnClsCd", ds_ctrtNo.getCellData(ctrtNorow[0], "taxnClsCd"));
        ds_cargoShiftingResults.setCellData(rowIndex, "berthCd", ds_ctrtNo.getCellData(ctrtNorow[0], "berthCd"));
      }
      break;
    case "sellCtrlAmtFcrc":
      if (oldValue === newValue) return;
      if (newValue > 0) {
        let crcCd = ds_cargoShiftingResults.getCellData(rowIndex, "crcCd");
        if (crcCd !== "") {
          if (crcCd === "KRW") {
            ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmt", newValue);
          } else {
            ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmt", newValue * ds_cargoShiftingResults.getCellData(rowIndex, "stdExchRt"));
          }
        }
      } else if (newValue == 0) {
        ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmt", 0);
      }
      if (newValue < 0) {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_007, ["매출조정금액외화"]);
        ds_cargoShiftingResults.setCellData(rowIndex, colid, oldValue);
        return false;
      }
      break;
    case "sellCtrlAmt":
      if (oldValue === newValue) return;
      if (newValue > 0) {
        if (ds_cargoShiftingResults.getCellData(rowIndex, "crcCd") === "KRW") {
          ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmtFcrc", 0);
        }
      } else if (newValue == 0) {
        ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmtFcrc", 0);
      }
      break;
    default:
      break;
  }
};

// 영대문자 변환 (본선관리번호)
scwin.applyUpper = function (value) {
  return value.toUpperCase();
};

// 소수점 3자리
scwin.fn_limitDecimal3 = function (value) {
  return scwin.fn_limitDecimal(value, 3);
};

// 계약번호 선택 formatter - choices 목록과 무관하게 값 그대로 표시
scwin.ctrtNoDetailFormatter = function (value) {
  return value || "";
};

// 소숫점 이하 자릿수 체크 + 천단위 콤마
// decimalLen : 소수점 자릿수 (기본값 3)
scwin.fn_limitDecimal = function (value, decimalLen) {
  if ($c.gus.cfIsNull($p, value)) return "";
  var len = decimalLen || 3;

  // 콤마 제거 후 처리
  var strValue = value.toString().replace(/,/g, "");
  var parts = strValue.split(".");
  var intPart = parts[0];

  // 소수점 이하 없으면 "0"을 len만큼 채움, 있으면 len자리로 자르고 부족하면 0으로 채움
  var decPart = parts.length > 1 ? parts[1].substring(0, len).padEnd(len, "0") : "0".repeat(len);

  // 천단위 콤마 적용
  var formatted = intPart.replace(/\B(?=(\d{3})+(?!\d))/g, ",");
  return formatted + "." + decPart;
};

// 매출항목 필터
scwin.filterSelpchItemCd = function (wrkStpCd) {
  ds_sellingItem.clearFilter();

  // 2. wrkStpCd 값에 따른 필터 분기 처리
  if (wrkStpCd === "0007") {
    // [조건 1] wrkStpCd가 "0007"인 경우: 매출항목("sellItemCd")이 "0177"인 것만 표시
    ds_sellingItem.setColumnFilter({
      type: "row",
      colIndex: "sellItemCd",
      key: "0177",
      condition: 'and',
      // 일치 조건
      exactMatch: true
    });
  } else {
    // [조건 2] wrkStpCd가 "0007"이 아닌 경우: 매출항목("sellItemCd")이 "0177"이 아닌 것만 표시
    ds_sellingItem.setColumnFilter({
      type: 'func',
      colIndex: "sellItemCd",
      key: fn_fi0177NotFilter,
      condition: "and"
    });
  }
};

// wrkStpCd가 "0007"이 아닌 경우: 매출항목("sellItemCd")이 "0177"이 아닌 것만 표시
var fn_fi0177NotFilter = function (cellData, tmpParam, rowIdx) {
  if (cellData.indexOf("0177") > -1) {
    return false;
  }
  return true; // return이 true인 경우 적용하고 false인 경우 넘김
};
scwin.ctrtNoOri = "";

// 매출항목 필터링
scwin.gr_cargoShiftingResults_onbeforeedit = function (rowIndex, columnIndex, value) {
  let columnId = gr_cargoShiftingResults.getColumnID(columnIndex);
  if (columnId === "selpchItemCd") {
    let wrkStpCd = ds_cargoShiftingResults.getCellData(rowIndex, "wrkStpCd");
    if (wrkStpCd === "0007") {
      scwin.clsCd = 1;
    } else {
      scwin.clsCd = 2;
    }
    scwin.filterSelpchItemCd(wrkStpCd);
  } else if (columnId === "ctrtNoDetail") {
    if (ds_ctrtNo.getTotalRow() == 0) {
      scwin.ctrtNoOri = ds_cargoShiftingResults.getCellData(rowIndex, "ctrtNoDetail");
    }

    // onrowindexchange에서 이미 ds_ctrtNo 로드됨 → 이 시점에 select로 전환
    var info = {
      inputType: "select",
      options: {
        emptyItem: "true",
        allowNotInList: "true"
      },
      itemSet: {
        nodeset: "data:ds_ctrtNo",
        label: "ctrtNoDetail",
        value: "ctrtNoDetail"
      }
    };

    // 첫 번째 행, "a" 컬럼에 해당하는 셀의 inputType을 select로 변경
    gr_cargoShiftingResults.setCellInputType(rowIndex, "ctrtNoDetail", info);
  }
  return true;
};
scwin.gr_cargoShiftingResults_onafteredit = function (rowIndex, columnIndex, value) {
  let colid = gr_cargoShiftingResults.getColumnID(columnIndex);
  if (colid === "selpchItemCd") {
    // filter 초기화
    ds_sellingItem.clearFilter();
  } else if (colid === "adptWt" || colid === "adptCbm") {
    let defaultValue = value == "" || value == null ? "0.000" : value;
    ds_cargoShiftingResults.setCellData(rowIndex, colid, defaultValue);
  } else if (colid === "ctrtNoDetail") {
    gr_cargoShiftingResults.setCellInputType(rowIndex, "ctrtNoDetail", {
      inputType: "text",
      emptyItem: "true"
    });

    // 계약번호 리스트 항목에 같은 값이 없으면 빈값처리되는 문제 해결을 위해 edit 전에 값 저장 후 셋팅
    if (value === "" && ds_ctrtNo.getTotalRow() == 0) {
      ds_cargoShiftingResults.setCellData(rowIndex, "ctrtNoDetail", scwin.ctrtNoOri);
    }
  }
};
